BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?parent ?parentType ?parentName WHERE {
  ?elem vocab:NamedElement_name "TMT-APS%20DDD" .
  ?elem vocab:Element_owner ?parent .
  ?parent rdf:type ?parentType .
  OPTIONAL { ?parent vocab:NamedElement_name ?parentName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?qualifiedName ?id WHERE {
  ?elem vocab:NamedElement_name ?name . 
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("TMT-APS%20DDD")))
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualifiedName }
  OPTIONAL { ?elem vocab:MDObject_ID ?id }
}

